function  [meanA,stdA] = fStdClmnElmntnV01(inptA,elmN)%% Return mean and std of column of input 2d array,% with exception on elimination number%% [meanR,stdR] = fStdClmnElmntnV01(inptA,elmN)%% inptA: input (m x n) array% elmN: elimination number, this number in input array will be neglected% from statistics, default = 0.%% meanA: (1 x n) array, mean of each column for input array% stdA: (1 x n) array, standard deviation of each column for input array%%% written by Kei Nakamura% ver.1: 2012/7/19 Thursday% created.%% main bodyif nargin==0    error('Not enough input arguments.');elseif nargin==1    elmN = 0;   % default 0 endlogicA = inptA ~= elmN; % logic to eliminate elements with elmN.meanA = sum(inptA.*logicA)./sum(logicA);[meanAG,~] = meshgrid(meanA,inptA(:,1));    % grid of mean anglemeanAG = meanAG.*logicA;                    % logic the grid to put 0.stdA = sum(abs(meanAG - inptA))./sum(logicA);   % standard dev
